def process_data(data_list, min_value, max_value):
    """
    Verilen listeyi işler ve her bir öğenin belirtilen minimum ve maksimum değerler
    arasında olup olmadığını doğrular.
    """
    assert isinstance(data_list, list), "data_list bir liste olmalıdır."
    assert len(data_list) > 0, "data_list boş olamaz."

    assert isinstance(min_value, (int, float)), "min_value bir sayı olmalıdır."
    assert isinstance(max_value, (int, float)), "max_value bir sayı olmalıdır."
    assert min_value <= max_value, "min_value, max_value'dan büyük olamaz."

    processed_results = []
    for item in data_list:
        assert isinstance(item, (int, float)), f"Listenin tüm öğeleri sayı olmalıdır, '{item}' sayı değil."
        assert min_value <= item <= max_value, f"'{item}', {min_value} ile {max_value} arasında olmalıdır."
        processed_results.append(item * 2) # Basit bir işlem örneği

    return processed_results

if __name__ == '__main__':
    # Geçerli kullanım örnekleri
    print(process_data([1, 2, 3, 4, 5], 1, 5))
    print(process_data([10.5, 12.0, 15.7], 10, 20))

    # Geçersiz kullanım örnekleri (AssertionError'a yol açar)
    try:
        process_data("bu bir string", 1, 5) # data_list liste değil
    except AssertionError as e:
        print(f"Hata: {e}")

    try:
        process_data([], 1, 5) # data_list boş
    except AssertionError as e:
        print(f"Hata: {e}")

    try:
        process_data([1, 2, "üç"], 1, 5) # Liste öğesi sayı değil
    except AssertionError as e:
        print(f"Hata: {e}")

    try:
        process_data([1, 2, 6], 1, 5) # Liste öğesi aralık dışında
    except AssertionError as e:
        print(f"Hata: {e}")

    try:
        process_data([1, 2, 3], 5, 1) # min_value > max_value
    except AssertionError as e:
        print(f"Hata: {e}")
